### 2. Security: Wildcard CORS Configuration
**Risk**: Cross-site request forgery, credential theft, session hijacking

```javascript
// ❌ CURRENT: Allows any origin
'Access-Control-Allow-Origin': '*'

// ✅ FIX: Strict origin validation
const ALLOWED_ORIGINS = new Set([
  'https://www.yourstore.com',
  'https://yourstore.com',
  'https://admin.yourstore.com',
  ...(process.env.STAGE === 'dev' ? ['http://localhost:3000'] : [])
]);

const corsMiddleware = (handler) => async (event, context) => {
  const origin = event.headers?.origin || event.headers?.Origin;
  const allowedOrigin = ALLOWED_ORIGINS.has(origin) ? origin : null;

  // Handle preflight
  if (event.httpMethod === 'OPTIONS') {
    return {
      statusCode: 204,
      headers: {
        'Access-Control-Allow-Origin': allowedOrigin || '',
        'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type,Authorization,X-Request-ID',
        'Access-Control-Allow-Credentials': 'true',
        'Access-Control-Max-Age': '86400',
      },
      body: '',
    };
  }

  const response = await handler(event, context);

  return {
    ...response,
    headers: {
      ...response.headers,
      'Access-Control-Allow-Origin': allowedOrigin || '',
      'Access-Control-Allow-Credentials': 'true',
      'Vary': 'Origin',
    },
  };
};
```

**Impact**: HIGH | **Effort**: LOW | **Timeline**: 1 day

